svg.script:
var selectedRegion = null;
document.querySelectorAll('.region').forEach(function(el) {
  el.addEventListener('click', function(e) {
    if (selectedRegion) selectedRegion.classList.remove('selected');
    selectedRegion = this;
    this.classList.add('selected');
    document.dispatchEvent(new CustomEvent('regionSelected', {
      detail: { name: this.getAttribute('data-name'), code: this.getAttribute('data-code') }
    }));
    e.stopPropagation();
  });
});
document.querySelector('svg').addEventListener('click', function() {
  if (selectedRegion) { selectedRegion.classList.remove('selected'); selectedRegion = null; }
});
